// Type declarations for lucide-react-native individual CJS icon modules.
// These paths are used by src/icons.ts for tree-shaken imports.
declare module 'lucide-react-native/dist/cjs/icons/*' {
  import type { LucideIcon } from 'lucide-react-native';
  const icon: LucideIcon;
  export default icon;
}
